/*
 * nextafter() test harness — prints (x_hex, y_hex, output_hex) triples.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x, double y)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    volatile double vy = y;
    g_acc += nextafter(vx, vy);
#else
    double r = nextafter(x, y);
    printf("%016llx %016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(y), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t x_bits, uint64_t y_bits)
{
    emit(u2d(x_bits), u2d(y_bits));
}

#ifndef EN_PERF
/* --- Dense sweep: 15x20 grid = 300 cases --- */
static void test_random_300(void)
{
    int nx = 15, ny = 20;
    for (int i = 0; i < nx; i++) {
        double x = -5.0 + 10.0 * (double)i / (double)(nx - 1);
        for (int j = 0; j < ny; j++) {
            double y = -5.0 + 10.0 * (double)j / (double)(ny - 1);
            emit(x, y);
        }
    }
}
#endif

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values as x (12) --- */
    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);  /* qNaN x, 1.0 y */
    emit_u(0x7ff0000000000001ULL, 0x3ff0000000000000ULL);  /* sNaN x, 1.0 y */
    emit_u(0xfff8000000000000ULL, 0x3ff0000000000000ULL);  /* -qNaN x, 1.0 y */
    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);  /* 1.0 x, qNaN y */
    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL);  /* +Inf x, 1.0 y */
    emit_u(0xfff0000000000000ULL, 0x3ff0000000000000ULL);  /* -Inf x, 1.0 y */
    emit_u(0x7ff0000000000000ULL, 0xfff0000000000000ULL);  /* +Inf x, -Inf y */
    emit_u(0xfff0000000000000ULL, 0x7ff0000000000000ULL);  /* -Inf x, +Inf y */
    emit_u(0x7ff0000000000000ULL, 0x7ff0000000000000ULL);  /* +Inf x, +Inf y (x==y) */
    emit_u(0xfff0000000000000ULL, 0xfff0000000000000ULL);  /* -Inf x, -Inf y (x==y) */
    emit_u(0x3ff0000000000000ULL, 0xfff0000000000000ULL);  /* 1.0 x, -Inf y (step down) */
    emit_u(0xbff0000000000000ULL, 0x7ff0000000000000ULL);  /* -1.0 x, +Inf y (step up) */

    /* --- Section 2: Subnormal x values, stepping toward 1.0 (8) --- */
    emit_u(0x0000000000000001ULL, 0x3ff0000000000000ULL);  /* min positive subnormal, toward 1.0 */
    emit_u(0x8000000000000001ULL, 0x3ff0000000000000ULL);  /* min negative subnormal, toward 1.0 */
    emit_u(0x0008000000000000ULL, 0x3ff0000000000000ULL);  /* mid positive subnormal, toward 1.0 */
    emit_u(0x8008000000000000ULL, 0x3ff0000000000000ULL);  /* mid negative subnormal, toward 1.0 */
    emit_u(0x000fffffffffffffULL, 0x3ff0000000000000ULL);  /* max subnormal, toward 1.0 */
    emit_u(0x800fffffffffffffULL, 0x3ff0000000000000ULL);  /* max negative subnormal, toward 1.0 */
    emit_u(0x0000000000000001ULL, 0x8000000000000000ULL);  /* min positive subnormal, toward -0.0 */
    emit_u(0x8000000000000001ULL, 0x0000000000000000ULL);  /* min negative subnormal, toward +0.0 */

    /* --- Section 3: Normal boundary x values (8) --- */
    emit_u(0x0010000000000000ULL, 0x0000000000000000ULL);  /* DBL_MIN toward 0: crosses normal/subnormal */
    emit_u(0x0010000000000000ULL, 0x3ff0000000000000ULL);  /* DBL_MIN toward 1.0 */
    emit_u(0x8010000000000000ULL, 0x0000000000000000ULL);  /* -DBL_MIN toward 0 */
    emit_u(0x8010000000000000ULL, 0xbff0000000000000ULL);  /* -DBL_MIN toward -1.0 */
    emit_u(0x0010000000000001ULL, 0x0000000000000000ULL);  /* one ULP above DBL_MIN, toward 0 */
    emit_u(0x001fffffffffffffULL, 0x3ff0000000000000ULL);  /* near DBL_MIN*2, toward 1.0 */
    emit_u(0x7feffffffffffffeULL, 0x7ff0000000000000ULL);  /* one ULP below DBL_MAX, toward +Inf */
    emit_u(0x7fefffffffffffffULL, 0x7ff0000000000000ULL);  /* DBL_MAX toward +Inf: returns +Inf */

    /* --- Section 4: x == y, no step taken (8) --- */
    emit(0.0, 0.0);
    emit(-0.0, -0.0);
    emit(1.0, 1.0);
    emit(-1.0, -1.0);
    emit(0.5, 0.5);
    emit(2.0, 2.0);
    emit_u(0x0010000000000000ULL, 0x0010000000000000ULL);  /* DBL_MIN == DBL_MIN */
    emit_u(0x7fefffffffffffffULL, 0x7fefffffffffffffULL);  /* DBL_MAX == DBL_MAX */

    /* --- Section 5: Zero crossing, stepping through +/-0.0 (8) --- */
    emit(0.0, 1.0);
    emit(0.0, -1.0);
    emit(-0.0, 1.0);
    emit(-0.0, -1.0);
    emit(0.0, 0.5);
    emit(0.0, -0.5);
    emit(-0.0, 0.5);
    emit(-0.0, -0.5);

    /* --- Section 6: Stepping across normal/subnormal boundary (8) --- */
    emit_u(0x000fffffffffffffULL, 0x3ff0000000000000ULL);  /* max subnormal stepping to first normal */
    emit_u(0x0010000000000000ULL, 0x8000000000000000ULL);  /* DBL_MIN stepping to max subnormal */
    emit_u(0x8010000000000000ULL, 0x0000000000000000ULL);  /* -DBL_MIN stepping toward -subnormal */
    emit_u(0x800fffffffffffffULL, 0xbff0000000000000ULL);  /* max neg subnormal stepping to -normal */
    emit_u(0x0000000000000002ULL, 0x0000000000000000ULL);  /* subnormal stepping toward zero */
    emit_u(0x8000000000000002ULL, 0x0000000000000000ULL);  /* neg subnormal stepping toward zero */
    emit_u(0x0000000000000001ULL, 0x0000000000000000ULL);  /* min subnormal stepping to +0.0 */
    emit_u(0x8000000000000001ULL, 0x8000000000000000ULL);  /* min neg subnormal stepping to -0.0 */

    /* --- Section 7: DBL_MAX boundary, overflow to Inf (8) --- */
    emit_u(0x7fefffffffffffffULL, 0x3ff0000000000000ULL);  /* DBL_MAX stepping down */
    emit_u(0x7feffffffffffffeULL, 0x7ff0000000000000ULL);  /* one ULP below DBL_MAX, stepping up */
    emit_u(0xffeffffffffffffeULL, 0xfff0000000000000ULL);  /* one ULP below -DBL_MAX, stepping away */
    emit_u(0xffefffffffffffffULL, 0x0000000000000000ULL);  /* -DBL_MAX stepping toward zero */
    emit_u(0x7fefffffffffffffULL, 0x7feffffffffffffeULL);  /* DBL_MAX stepping back by 1 ULP */
    emit_u(0xffefffffffffffffULL, 0xffeffffffffffffeULL);  /* -DBL_MAX stepping back by 1 ULP */
    emit(-DBL_MAX, -INFINITY);                              /* -DBL_MAX toward -Inf: returns -Inf */
    emit(DBL_MAX, INFINITY);                                /* DBL_MAX toward +Inf: returns +Inf */

    /* --- Section 8: Sign crossing (negative to positive and vice versa) (8) --- */
    emit(-1.0, 1.0);   /* negative toward positive */
    emit(1.0, -1.0);   /* positive toward negative */
    emit(-0.5, 0.5);
    emit(0.5, -0.5);
    emit(-2.0, 2.0);
    emit(2.0, -2.0);
    emit(-1.0e10, 1.0e10);
    emit(1.0e10, -1.0e10);

    /* --- Section 9: y is +/-Inf (step in extreme direction) (8) --- */
    emit(1.0, INFINITY);
    emit(1.0, -INFINITY);
    emit(-1.0, INFINITY);
    emit(-1.0, -INFINITY);
    emit(0.5, INFINITY);
    emit(0.5, -INFINITY);
    emit(1.0e15, INFINITY);
    emit(-1.0e15, -INFINITY);

    /* --- Section 10: General normal range coverage (24) --- */
    emit(1.0, 2.0);          /* step up from 1.0 */
    emit(1.0, 0.0);          /* step down from 1.0 */
    emit(2.0, 1.0);          /* step down from 2.0 */
    emit(2.0, 3.0);          /* step up from 2.0 */
    emit(-1.0, -2.0);        /* step down from -1.0 */
    emit(-1.0, 0.0);         /* step up from -1.0 */
    emit(0.5, 0.0);          /* step toward zero from 0.5 */
    emit(0.5, 1.0);          /* step away from zero at 0.5 */
    emit(-0.5, 0.0);         /* step toward zero from -0.5 */
    emit(-0.5, -1.0);        /* step away from zero at -0.5 */
    emit(10.0, 5.0);
    emit(10.0, 20.0);
    emit(-10.0, -5.0);
    emit(-10.0, -20.0);
    emit(100.0, 0.0);
    emit(100.0, 200.0);
    emit(1.0e15, 0.0);
    emit(1.0e15, 2.0e15);
    emit(-1.0e15, 0.0);
    emit(-1.0e15, -2.0e15);
    emit_u(0x3fefffffffffffffULL, 0x3ff0000000000000ULL);  /* one ULP below 1.0, step to 1.0 */
    emit_u(0x3ff0000000000001ULL, 0x3ff0000000000000ULL);  /* one ULP above 1.0, step to 1.0 */
    emit_u(0x3ff0000000000000ULL, 0x3ff0000000000001ULL);  /* 1.0, step one ULP up */
    emit_u(0x3ff0000000000000ULL, 0x3fefffffffffffffULL);  /* 1.0, step one ULP down */
}

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_random_300();
#endif
    return 0;
}

